import asyncio
from typing import List, Callable, Any

class AsyncPipeline:
    def __init__(self):
        self.stages: List[Callable] = []

    def add_stage(self, fn: Callable) -> "AsyncPipeline":
        self.stages.append(fn)
        return self

    async def run(self, items: List[Any]) -> List[Any]:
        results = []
        for item in items:
            value = item
            for stage in self.stages:
                # Assuming synchronous execution context for run() based on current tests
                try:
                    if asyncio.iscoroutinefunction(stage):
                        # This branch is only hit if a user manually passes async stages to run, 
                        # which the original implementation wrongly tried to call sync. 
                        # To fix this method defensively, we await it.
                        value = await stage(value)
                    else:
                        value = stage(value)
                except TypeError as e:
                     # Handle cases where stages might not be compatible if mixed modes are used incorrectly
                     # For now, let's assume the calling context handles this or only uses compatible types.
                     value = stage(value)

            results.append(value)
        return results

    async def run_parallel(self, items: List[Any]) -> List[Any]:
        tasks = [self._process(item) for item in items]
        return await asyncio.gather(*tasks)

    async def _process(self, item: Any) -> Any:
        value = item
        for stage in self.stages:
            if asyncio.iscoroutinefunction(stage):
                # Must await the async function call to get the result value
                value = await stage(value) 
            else:
                # Synchronous stage execution
                value = stage(value)
        return value

